@namespace sv_6c03f1e9cc954ff781f4923bba12cf91.Components.Pages.Settings
@using sv_6c03f1e9cc954ff781f4923bba12cf91.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Profile</h4>

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else
{
    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="mb-3">
                <label class="form-label">Avatar Preview</label>
                <div class="avatar-preview mb-2">
                    <img src="@_avatarUrl" alt="Avatar" class="rounded-circle img-fluid"
                         style="width:120px;height:120px;object-fit:cover;border:3px solid #dee2e6;" />
                </div>
                <small class="text-muted text-break d-block">@_avatarUrl</small>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@_saving">
            Discard Changes
        </button>
    </div>
}

@code {
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

