    private string PreviewClasses => _theme switch
    {
        "Dark" => "text-light",
        _ => ""
    };

    private string PreviewStyle => _theme switch
    {
        "Dark" => "background-color: #1a1a2e; color: #e0e0e0; transition: all 0.3s;",
        "System" => "background-color: #f0f0f5; color: #333; transition: all 0.3s;",
        _ => "background-color: #fff; color: #212529; transition: all 0.3s;"
    };

    private string FontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _successMessage = "Appearance settings saved!";
        _saving = false;
    }
}

