@namespace sv_6c03f1e9cc954ff781f4923bba12cf91.Components.Pages.Settings
@using sv_6c03f1e9cc954ff781f4923bba12cf91.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                                   value="@theme" checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="theme-@theme">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                                   value="@size" checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="fs-@size">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body">
                    <h6 class="card-title">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-body d-flex justify-content-between align-items-center">
                    <h6 class="mb-0">Compact Mode</h6>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" @bind="_compactMode"
                               style="transform: scale(1.3);" />
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <div class="card">
                <div class="card-header">Live Preview</div>
                <div class="card-body @PreviewClasses" style="@PreviewStyle">
                    <h5 style="@FontStyle">Dashboard</h5>
                    <p style="@FontStyle">
                        This is a preview of your selected appearance settings.
                        The theme is <strong>@_theme</strong>, font size is <strong>@_fontSize</strong>,
                        and the language is <strong>@_language</strong>.
                    </p>
                    <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                        <button class="btn btn-sm btn-primary" style="@FontStyle">Primary</button>
                        <button class="btn btn-sm btn-secondary" style="@FontStyle">Secondary</button>
                        <button class="btn btn-sm btn-outline-dark" style="@FontStyle">Outline</button>
                    </div>
                    <div class="@(_compactMode ? "p-1" : "p-2") border rounded" style="@FontStyle">
                        <small>@(_compactMode ? "Compact spacing active" : "Standard spacing active")</small>
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private string PreviewClasses => _theme switch
    {
        "Dark" => "text-light",
        _ => ""
    };

    private string PreviewStyle => _theme switch
    {
        "Dark" => "background-color: #1a1a2e; color: #e0e0e0; transition: all 0.3s;",
        "System" => "background-color: #f0f0f5; color: #333; transition: all 0.3s;",
        _ => "background-color: #fff; color: #212529; transition: all 0.3s;"
    };

    private string FontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _successMessage = "Appearance settings saved!";
        _saving = false;
    }
}

