@page "/settings"
@namespace sv_6c03f1e9cc954ff781f4923bba12cf91.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <aside class="settings-nav">
        <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />
    </aside>
    <section class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </section>
</div>

@code {
    private string _activeSection = "Profile";
}

.settings-layout {
    display: flex;
    gap: 2rem;
    min-height: 70vh;
}

.settings-nav {
    flex: 0 0 220px;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

::deep .settings-sidebar {
    position: sticky;
    top: 1rem;
}

::deep .sidebar-title {
    padding: 0.75rem 1rem;
    margin-bottom: 0.25rem;
    color: #6c757d;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

