    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1rem;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    color: #495057;
    border-radius: 0.375rem;
    cursor: pointer;
    font-size: 0.95rem;
    transition: background-color 0.15s, color 0.15s;
}

::deep .sidebar-link:hover {
    background-color: #f8f9fa;
    color: #212529;
}

::deep .sidebar-link.active {
    background-color: #0d6efd;
    color: #fff;
}

::deep .sidebar-icon {
    font-size: 1.1rem;
}

